/**
 * SafetyPro AI — fix_audit_compliance.js
 * RESTORES correct version with dark theme + adds minimal footer fix
 * Run: cd C:\safetypro_complete_frontend && node fix_audit_compliance.js
 */
const fs = require('fs'), path = require('path'), zlib = require('zlib');
const fp = path.join(process.cwd(), 'safetypro_audit_compliance.html');

// Backup current (broken) file
const bk = fp.replace('.html', '_bk_broken_' + Date.now() + '.html');
if (fs.existsSync(fp)) { fs.copyFileSync(fp, bk); console.log('Backed up broken file:', path.basename(bk)); }

// Restore clean version
const clean = zlib.gunzipSync(Buffer.from('', 'base64')).toString('utf8');
fs.writeFileSync(fp, clean, 'utf8');
console.log('Restored clean version:', Math.round(clean.length/1024) + 'KB');
console.log('Has dark theme:', clean.includes('0B0F14'));
console.log('Has footer fix:', clean.includes('sp-ac-footer-fix'));
console.log('Has SafetyPro Global:', clean.includes('SafetyPro Global'));
console.log('\nDeploy: npx wrangler pages deploy . --project-name safetypro-frontend');
